        '[{"value":"National Accreditation Services","langId":1},{"value":"إدارة الإعتماد الوطني","langId":2}]',
      goupOrder: 0,
      services:
        '[{"Id":2,"Name":"CABs Pre-Registration","OrderNumber":1,"serviceName":[{"value":"Issue a Non Objection Certificate","langId":1},{"value":"اصدار شهادة عدم ممانعة للتسجيل المبدئي لجهات تقييم المطابقة","langId":2}],"serviceDescription":[{"value":"<p><strong>CABs Registration<\\/strong><br \\/>According to <em>UAE Cabinet Decree No. 35 for the year 2015 regarding UAE System for Control of CABs<\\/em>, registration is mandatory for all CABs in UAE, either private or government, with Emirates Authority for Standardization and Metrology (ESMA). The exceptions are medical laboratories, research and development laboratories, and private laboratories for personal use or training\\/learning purposes or for quality control purposes in the factories. The basis for registration fees and penalties for violation is &ldquo;<em>UAE Cabinet Resolution No. (36) for the year 2015 Regarding Fees for Control Services of Conformity Assessment Bodies<\\/em>&rdquo;.<\\/p>\\n<p><strong>Pre-Registration&nbsp;(Issue of NOC by NAD)<\\/strong><br \\/>The private CABs shall apply for pre-registration in case if the scope of registration&nbsp;is not mentioned in their trade license. Current scopes are&nbsp;testing, calibration, inspection, and certification.<br \\/>The CAB shall submit separate application for each scope.<\\/p>\\n<p><strong>Procedure of Pre-Registration<\\/strong><\\/p>\\n<ol>\\n<li>The private CABs shall obtain the Reserved Trade License (RTL) from the licensing authority.<\\/li>\\n<li>CAB must apply online and pay fees.<\\/li>\\n<li>NAD shall issue the No objection Letter to the CAB<\\/li>\\n<li>The CAB shall proceed to licensing authority, complete the required formalities and obtain trade license (in the scopes in which it wishes to get registered with NAD).<\\/li>\\n<\\/ol>","langId":1},{"value":"<p>التسجيل المبدئي لجهات تقييم المطابقة لإصدار شهادة عدم الممانعة<\\/p>","langId":2}],"StartStageID":19,"ServiceIcon":"CABs NOC","Settings":"{\\"KhadamatiSequence\\":\\"114-28-004-000\\",\\"appNumberSetting\\":{\\"prefix\\":\\"PR\\", \\"addYear\\":true, \\"yearFormat\\":\\"yy\\"}, \\"viewActionUrls\\":[{\\"lang\\":\\"en\\",\\"url\\":\\"https:\\/\\/moiat.gov.ae\\/en\\/services\\/issue-a-non-objection-certificate\\"},{\\"lang\\":\\"ar\\",\\"url\\":\\"https:\\/\\/moiat.gov.ae\\/ar\\/services\\/issue-a-non-objection-certificate\\"}],\\"TargetServiceTimeMinutes\\":0,\\"MainSectorId\\":2,\\"MainServiceId\\":14}","FavouriteService":"true","IsNewService":"No"},{"Id":5,"Name":"NOC Extension","OrderNumber":2,"serviceName":[{"value":"Extend No Objection Certificate for Registration of Conformity Assessment Bodies","langId":1},{"value":"تمديد شهادة عدم ممانعة للتسجيل المبدئي لجهات تقييم المطابقة","langId":2}],"serviceDescription":[{"value":"<p>Non conformity certificate validity extension. User may apply for this service to get 6 more months on their NOC certificate validity.<\\/p>","langId":1},{"value":"<p>تمديد صلاحية شهادة عدم الممانعة<\\/p>","langId":2}],"StartStageID":32,"ServiceIcon":"NOC EXTEND","Settings":"{\\"appNumberSetting\\":{\\"prefix\\":\\"PR-R\\", \\"addYear\\":true, \\"yearFormat\\":\\"yy\\"},\\"MainSectorId\\":2,\\"MainServiceId\\":17}","FavouriteService":"false","IsNewService":"No"}]',
