      services:
        '[{"Id":1025,"Name":"Halal Registration","OrderNumber":5,"serviceName":[{"value":"Registration of Halal Certification Bodies ","langId":1},{"value":"تسجيل جهات منح شهادات الحلال","langId":2}],"serviceDescription":[{"value":"<p>Registration of Halal Certification Bodies<\\/p>","langId":1},{"value":"<p>تسجيل جهات منح شهادات الحلال<\\/p>","langId":2}],"StartStageID":1094,"ServiceIcon":"New HCB Reg","Settings":"{\\"KhadamatiSequence\\":\\"114-35-001-000\\", \\"appNumberSetting\\":{\\"prefix\\":\\"RH\\", \\"addYear\\":true, \\"yearFormat\\":\\"yy\\"}, \\"viewActionUrls\\":[{\\"lang\\":\\"en\\",\\"url\\":\\"https:\\/\\/moiat.gov.ae\\/en\\/services\\/registration-of-halal-certification-bodies\\"},{\\"lang\\":\\"ar\\",\\"url\\":\\"https:\\/\\/moiat.gov.ae\\/ar\\/services\\/registration-of-halal-certification-bodies\\"}],\\"TargetServiceTimeMinutes\\":14400,\\"MainSectorId\\":2,\\"MainServiceId\\":69}","FavouriteService":"false","IsNewService":"No"},{"Id":1026,"Name":"Halal Registration Renewal","OrderNumber":6,"serviceName":[{"value":"Renew Registration of Halal Certification Bodies ","langId":1},{"value":"تجديد تسجيل جهات منح شهادات الحلال","langId":2}],"serviceDescription":[{"value":"<p>Renewal of the Registration of Halal Certification Bodies<\\/p>","langId":1},{"value":"<p>تجديد التسجيل الحلال<\\/p>","langId":2}],"StartStageID":1099,"ServiceIcon":"Renew HCB Reg","Settings":"{\\"KhadamatiSequence\\":\\"114-35-001-001\\", \\"appNumberSetting\\":{\\"prefix\\":\\"RH-R\\", \\"addYear\\":true, \\"yearFormat\\":\\"yy\\"}, \\"viewActionUrls\\":[{\\"lang\\":\\"en\\",\\"url\\":\\"https:\\/\\/moiat.gov.ae\\/en\\/services\\/renewal-of-registration-of-halal-certification-bodies\\"},{\\"lang\\":\\"ar\\",\\"url\\":\\"https:\\/\\/moiat.gov.ae\\/ar\\/services\\/renewal-of-registration-of-halal-certification-bodies\\"}],\\"TargetServiceTimeMinutes\\":14400,\\"MainSectorId\\":2,\\"MainServiceId\\":68}","FavouriteService":"false","IsNewService":"No"},{"Id":1066,"Name":"Halal Registration Modification","OrderNumber":7,"serviceName":[{"value":"Amendment on the Registration of Halal Certification Bodies Certificate","langId":1},{"value":"تعديل نشاط في شهادة تسجيل جهات منح شهادات الحلال ","langId":2}],"serviceDescription":[{"value":"<p>Amendment on the Registration of Halal Certification Bodies Certificate<\\/p>","langId":1},{"value":"<p>تعديل نشاط في شهادة تسجيل جهات منح شهادات الحلال ​​​​​​​<\\/p>\\n<p>&nbsp;<\\/p>","langId":2}],"StartStageID":1250,"ServiceIcon":"Halal EDIT","Settings":"{\\"KhadamatiSequence\\":\\"114-35-001-002\\", \\"appNumberSetting\\":{\\"prefix\\":\\"RH-M\\", \\"addYear\\":true, \\"yearFormat\\":\\"yy\\"}, \\"viewActionUrls\\":[{\\"lang\\":\\"en\\",\\"url\\":\\"https:\\/\\/moiat.gov.ae\\/en\\/services\\/amendment-on-the-registration-of-halal-certification-bodies-certificate\\"},{\\"lang\\":\\"ar\\",\\"url\\":\\"https:\\/\\/moiat.gov.ae\\/ar\\/services\\/amendment-on-the-registration-of-halal-certification-bodies-certificate\\"}],\\"TargetServiceTimeMinutes\\":14400,\\"MainSectorId\\":2,\\"MainServiceId\\":70}","FavouriteService":"false","IsNewService":"No"},{"Id":1070,"Name":"HALAL OLD","OrderNumber":8,"serviceName":[{"value":"Submit Old Halal Certificate","langId":1},{"value":"تقديم شهادة حلال قديمة","langId":2}],"serviceDescription":[{"value":"<p>Submit Old Halal Certificate<\\/p>","langId":1},{"value":"<p>تقديم شهادة حلال قديمة<\\/p>","langId":2}],"StartStageID":1272,"ServiceIcon":"HALAL OLD","Settings":"{\\"appNumberSetting\\":{\\"prefix\\":\\"RHO\\", \\"addYear\\":true, \\"yearFormat\\":\\"yy\\"},\\"MainServiceId\\":85,\\"MainSectorId\\":2,\\"OldPrefix\\":\\"RHO\\"}","FavouriteService":"false","IsNewService":"No"}]',
